import React from 'react';

const stays = [
  {
    name: 'SafeStay Hostel',
    location: 'Paris, France',
    image: 'https://images.unsplash.com/photo-1506744038136-46273834b3fb',
    verified: true,
    description: 'Women-only hostel with 24/7 security and great reviews.',
  },
  {
    name: 'Comfort Inn',
    location: 'Berlin, Germany',
    image: 'https://images.unsplash.com/photo-1519125323398-675f0ddb6308',
    verified: true,
    description: 'Verified by TravElle community for safety and comfort.',
  },
];

const VerifiedStays: React.FC = () => (
  <div className="max-w-4xl mx-auto p-6">
    <h2 className="text-2xl font-bold mb-6">Verified Stays</h2>
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
      {stays.map((stay, idx) => (
        <div key={idx} className="bg-white rounded-lg shadow p-4 flex flex-col">
          <img src={stay.image} alt={stay.name} className="h-40 w-full object-cover rounded mb-4" />
          <h3 className="text-lg font-semibold">{stay.name}</h3>
          <p className="text-sm text-gray-600">{stay.location}</p>
          <p className="mt-2">{stay.description}</p>
          {stay.verified && (
            <span className="mt-2 inline-block bg-green-100 text-green-700 px-2 py-1 rounded text-xs font-bold">
              Verified
            </span>
          )}
        </div>
      ))}
    </div>
  </div>
);

export default VerifiedStays;
